func fetchAllPhotos(ids: [String]) async throws -> [UIImage] {
    try await withThrowingTaskGroup(of: UIImage.self) { group in
        for id in ids {
            group.addTask { try await fetchPhoto(id: id) }
        }

        var photos = [UIImage]()
        for try await photo in group {
            photos.append(photo)
        }
        return photos
    }
}

